import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { 
  createMint, 
  getOrCreateAssociatedTokenAccount, 
  mintTo 
} from '@solana/spl-token';

export default function DeployPage() {
  const { connection, wallets, addLog, setDeployedToken } = useApp();
  const [tokenName, setTokenName] = useState('');
  const [tokenSymbol, setTokenSymbol] = useState('');
  const [decimals, setDecimals] = useState(9);
  const [supply, setSupply] = useState(1000000);
  const [isDeploying, setIsDeploying] = useState(false);
  const [selectedWallet, setSelectedWallet] = useState(0);

  const deployToken = async () => {
    if (!connection) {
      addLog('No connection to Solana', 'error');
      return;
    }

    if (wallets.length === 0) {
      addLog('Create a wallet first!', 'error');
      return;
    }

    const wallet = wallets[selectedWallet];

    try {
      setIsDeploying(true);
      addLog('Starting token deployment...', 'info');

      // Create mint - CRITICAL: pass the keypair to sign!
      addLog('Creating mint account...', 'info');
      const mint = await createMint(
        connection,
        wallet.keypair,           // PAYER (needs private key to sign)
        wallet.keypair.publicKey, // Mint authority
        wallet.keypair.publicKey, // Freeze authority  
        decimals
      );

      addLog('Mint created: ' + mint.toString().slice(0, 8) + '...', 'success');

      // Create associated token account
      addLog('Creating token account...', 'info');
      const tokenAccount = await getOrCreateAssociatedTokenAccount(
        connection,
        wallet.keypair,           // PAYER (needs private key to sign)
        mint,
        wallet.keypair.publicKey  // Owner
      );

      addLog('Token account created', 'success');

      // Mint initial supply
      if (supply > 0) {
        addLog('Minting initial supply...', 'info');
        await mintTo(
          connection,
          wallet.keypair,           // PAYER (needs private key to sign)
          mint,
          tokenAccount.address,
          wallet.keypair.publicKey, // Mint authority
          supply * Math.pow(10, decimals)
        );
        addLog('Minted ' + supply + ' tokens', 'success');
      }

      // Save deployed token info
      const tokenInfo = {
        mint: mint.toString(),
        name: tokenName || 'My Token',
        symbol: tokenSymbol || 'MTK',
        decimals,
        supply,
        owner: wallet.publicKey,
        tokenAccount: tokenAccount.address.toString()
      };

      setDeployedToken(tokenInfo);
      addLog('Token deployed successfully!', 'success');

    } catch (err) {
      console.error('Deployment failed:', err);
      addLog('Deployment failed: ' + err.message, 'error');
    } finally {
      setIsDeploying(false);
    }
  };

  return (
    <div>
      <div className="glass-panel">
        <div className="section-label">// DEPLOY NEW TOKEN</div>

        {wallets.length === 0 ? (
          <p style={{ color: '#ff4444' }}>⚠️ Create a wallet in the Wallets tab first!</p>
        ) : (
          <>
            <label>Select Wallet (will pay fees)</label>
            <select 
              value={selectedWallet} 
n              onChange={e => setSelectedWallet(Number(e.target.value))}
              style={{ width: '100%', marginBottom: '16px' }}
            >
              {wallets.map((w, i) => (
                <option key={w.publicKey} value={i}>
                  {w.name} ({w.publicKey.slice(0, 8)}...)
                </option>
              ))}
            </select>

            <label>Token Name</label>
            <input
              type="text"
              value={tokenName}
              onChange={e => setTokenName(e.target.value)}
              placeholder="My Token"
              style={{ width: '100%', marginBottom: '12px' }}
            />

            <label>Token Symbol</label>
            <input
              type="text"
              value={tokenSymbol}
              onChange={e => setTokenSymbol(e.target.value)}
              placeholder="MTK"
              style={{ width: '100%', marginBottom: '12px' }}
            />

            <label>Decimals (0-9)</label>
            <input
              type="number"
              value={decimals}
              onChange={e => setDecimals(Number(e.target.value))}
              min="0"
              max="9"
              style={{ width: '100%', marginBottom: '12px' }}
            />

            <label>Initial Supply</label>
            <input
              type="number"
              value={supply}
              onChange={e => setSupply(Number(e.target.value))}
              style={{ width: '100%', marginBottom: '16px' }}
            />

            <button 
              className="btn-primary" 
              onClick={deployToken}
              disabled={isDeploying}
            >
              {isDeploying ? 'Deploying...' : 'Deploy Token'}
            </button>
          </>
        )}
      </div>

      <div className="glass-panel">
        <div className="section-label">// INFO</div>
        <p style={{ fontSize: '12px', color: '#666' }}>
          Wallet needs SOL for fees. The selected wallet will be the mint authority.
        </p>
      </div>
    </div>
  );
}
